sql:
SELECT name, website, contact_email
FROM businesses
WHERE industry = 'Technology' AND company_size = '1-10 employees';

SELECT role_id, COUNT(user_id) AS Total_Users
FROM user_businesses
GROUP BY role_id;

SELECT * 
FROM review_comments 
WHERE content LIKE '%example%';

SELECT product_id, COUNT(rating_id) AS total_ratings
FROM ratings
GROUP BY product_id;

external_knowledge:
- "stand taller than their peers" means the business has an above-average company size compared to others in the same industry;
- "thrive" indicates active businesses with a significant presence within their industry;
- "segment of companies of their size" represents the group of businesses categorized by the same company size;
- "bustling market" is a metaphorical expression representing the active business environment.

